<?php require_once 'config.php'; if (!isset($_SESSION['user_id'])) { http_response_code(401); exit; } header('Content-Type: application/json'); $user_id = $_SESSION['user_id']; $db = getDB(); $limit = $_GET['limit'] ?? 10; $stmt = $db->prepare("SELECT id, nombre_cliente, numero_telefono, estado, fecha_envio FROM whatsapp_audit_log WHERE reseller_id = ? ORDER BY fecha_envio DESC LIMIT ?"); $stmt->execute([$user_id, $limit]); $notificaciones = $stmt->fetchAll(PDO::FETCH_ASSOC); $stmt = $db->prepare("SELECT COUNT(*) as total FROM whatsapp_audit_log WHERE reseller_id = ? AND estado = 'enviado'"); $stmt->execute([$user_id]); $total = $stmt->fetch()['total']; $stmt = $db->prepare("SELECT COUNT(*) as pendientes FROM whatsapp_audit_log WHERE reseller_id = ? AND estado = 'pendiente'"); $stmt->execute([$user_id]); $pendientes = $stmt->fetch()['pendientes']; echo json_encode(['success' => true, 'notificaciones' => $notificaciones, 'total_enviados' => $total, 'pendientes' => $pendientes, 'timestamp' => date('Y-m-d H:i:s')]);
